#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1005;
int n,m,e,match[N],vis[N];
vector<int> g[N];
bool dfs(int u,int f,int flag)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		if(vis[v]!=flag)
		{
			vis[v]=flag;
			if((match[v]==-1)||dfs(match[v],v,flag))
			{
				match[v]=u;
				return 1;
			}
		}
	}
	return 0;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>e;
	for(int i=1;i<=e;i++)
	{
		int u,v;
		cin>>u>>v;
		v+=n;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	int cnt=0;
	memset(match,-1,sizeof(match));
	for(int i=1;i<=n+m;i++)
	{
		if(dfs(i,0,i))
		{
			cnt++;
		}
	}
	cout<<cnt;
	return 0;
}
